using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap a REST API (JSONPlaceholder) via HttpClient.
/// Uses constructor injection — the SDK resolves DI services automatically.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Get a post by its ID from the REST API.")]
    public async Task<string> GetPost(
        [Description("The numeric post ID (1-100)")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching post {Id}", id);
        var post = await httpClient.GetFromJsonAsync<JsonElement>(
            $"posts/{id}", cancellationToken);
        return JsonSerializer.Serialize(post, JsonOptions);
    }

    [McpServerTool, Description("Search posts by user ID. Returns all posts authored by that user.")]
    public async Task<string> GetPostsByUser(
        [Description("The user ID to filter posts by")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching posts for user {UserId}", userId);
        var posts = await httpClient.GetFromJsonAsync<JsonElement>(
            $"posts?userId={userId}", cancellationToken);
        return JsonSerializer.Serialize(posts, JsonOptions);
    }

    [McpServerTool, Description("Get comments on a specific post.")]
    public async Task<string> GetComments(
        [Description("The post ID to retrieve comments for")] int postId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching comments for post {PostId}", postId);
        var comments = await httpClient.GetFromJsonAsync<JsonElement>(
            $"posts/{postId}/comments", cancellationToken);
        return JsonSerializer.Serialize(comments, JsonOptions);
    }

    [McpServerTool, Description("Look up a user profile by user ID.")]
    public async Task<string> GetUser(
        [Description("The user ID (1-10)")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching user {Id}", id);
        var user = await httpClient.GetFromJsonAsync<JsonElement>(
            $"users/{id}", cancellationToken);
        return JsonSerializer.Serialize(user, JsonOptions);
    }
}

